Here’s a Python function to extract the release year of 'Baltimore Oriole' by Hoagy Carmichael:
python
songs = [
    {"title": "Baltimore Oriole", "artist": "Hoagy Carmichael", "year": 1942},
    {"title": "Skylark", "artist": "Hoagy Carmichael", "year": 1942},
    {"title": "How Little We Know", "artist": "Lauren Bacall", "year": 1944}
]

def get_release_year(title, artist):
    for song in songs:
        if song["title"] == title and song["artist"] == artist:
            return song["year"]
    return None

print(get_release_year("Baltimore Oriole", "Hoagy Carmichael"))  # Output: 1942
